export { Stepper } from "./stepper";
export type {
  StepperMode,
  StepperProgressContext,
  StepperProps,
  StepperStep,
  StepperStepState,
} from "./stepper";

.mrg-stepper {
  color: var(--mrg-semantic-color-foreground-primary);
  display: grid;
  font-family: var(--mrg-semantic-font-family-prose);
  gap: var(--mrg-semantic-space-stack-md);
  min-inline-size: 0;
}

.mrg-stepper progress {
  accent-color: var(--mrg-semantic-color-brand-action);
  inline-size: 100%;
}

.mrg-stepper__summary {
  background: var(--mrg-semantic-color-background-surface);
  border-block: var(--mrg-semantic-border-width-default) solid
    var(--mrg-semantic-color-border-subtle);
  color: var(--mrg-semantic-color-foreground-muted);
  display: block;
  padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-space-inset-md);
}

.mrg-stepper ol {
  display: flex;
  list-style: none;
  margin: 0;
  min-inline-size: 0;
  padding: 0;
}

.mrg-stepper li {
  flex: 1 1 0;
  min-inline-size: 0;
  position: relative;
}

.mrg-stepper li:not(:last-child)::after {
  background: var(--mrg-semantic-color-border-strong);
  block-size: var(--mrg-semantic-border-width-strong);
  content: "";
  inline-size: calc(100% - var(--mrg-semantic-size-target-preferred));
  inset-block-start: calc(var(--mrg-semantic-size-target-preferred) / 2);
  inset-inline-start: calc(50% + var(--mrg-semantic-size-target-preferred) / 2);
  position: absolute;
}

.mrg-stepper li[data-state="complete"]::after {
  background: var(--mrg-semantic-color-brand-action);
}

.mrg-stepper__control {
  align-items: center;
  background: transparent;
  border: 0;
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  color: inherit;
  display: flex;
  flex-direction: column;
  font: inherit;
  gap: var(--mrg-semantic-space-stack-sm);
  inline-size: 100%;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: 0;
  padding: var(--mrg-semantic-space-inset-xs);
  position: relative;
  text-align: center;
  transition: background-color var(--mrg-semantic-motion-duration-transition)
    var(--mrg-semantic-motion-easing-standard);
  z-index: var(--mrg-semantic-layer-base);
}

button.mrg-stepper__control {
  cursor: pointer;
}

button.mrg-stepper__control:hover {
  background: var(--mrg-semantic-color-background-surface);
}

.mrg-stepper__marker {
  align-items: center;
  background: var(--mrg-semantic-color-background-canvas);
  border: var(--mrg-semantic-border-width-strong) solid var(--mrg-semantic-color-border-strong);
  border-radius: var(--mrg-semantic-radius-control);
  box-sizing: border-box;
  display: inline-flex;
  font-weight: var(--mrg-semantic-font-weight-strong);
  justify-content: center;
  min-block-size: var(--mrg-semantic-size-target-preferred);
  min-inline-size: var(--mrg-semantic-size-target-preferred);
  transition:
    background-color var(--mrg-semantic-motion-duration-transition)
      var(--mrg-semantic-motion-easing-standard),
    border-color var(--mrg-semantic-motion-duration-transition)
      var(--mrg-semantic-motion-easing-standard);
}

.mrg-stepper li[data-state="complete"] .mrg-stepper__marker,
.mrg-stepper li[data-state="current"] .mrg-stepper__marker {
  background: var(--mrg-semantic-color-selection-background);
  border-color: var(--mrg-semantic-color-selection-border);
  color: var(--mrg-semantic-color-selection-foreground);
}

.mrg-stepper li[data-error] .mrg-stepper__marker {
  background: var(--mrg-semantic-color-status-danger-background);
  border-color: var(--mrg-semantic-color-status-danger-border);
  color: var(--mrg-semantic-color-status-danger-foreground);
}

.mrg-stepper__copy {
  display: grid;
  gap: var(--mrg-semantic-space-stack-xs);
  min-inline-size: 0;
}

.mrg-stepper__copy > span {
  font-weight: var(--mrg-semantic-font-weight-label);
  overflow-wrap: anywhere;
}

.mrg-stepper__copy small {
  color: var(--mrg-semantic-color-foreground-muted);
  font-size: var(--mrg-semantic-font-size-label);
  font-weight: var(--mrg-semantic-font-weight-body);
}

.mrg-stepper__control[aria-current="step"] .mrg-stepper__copy > span {
  color: var(--mrg-semantic-color-brand-action);
  font-weight: var(--mrg-semantic-font-weight-strong);
}

.mrg-stepper li[data-error] .mrg-stepper__copy > span {
  color: var(--mrg-semantic-color-status-danger-foreground);
}

.mrg-stepper__control[aria-disabled="true"] {
  color: var(--mrg-semantic-color-foreground-disabled);
}

.mrg-stepper__control:focus-visible {
  box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
    var(--mrg-component-focus-indicator-contrast-background);
  outline: var(--mrg-component-focus-indicator-width) solid
    var(--mrg-component-focus-indicator-color);
  outline-offset: var(--mrg-component-focus-indicator-offset);
}

.mrg-stepper__announcement {
  clip: rect(0 0 0 0);
  clip-path: inset(50%);
  block-size: 1px;
  inline-size: 1px;
  overflow: hidden;
  position: absolute;
  white-space: nowrap;
}

.mrg-stepper__visually-hidden {
  block-size: 1px;
  clip: rect(0 0 0 0);
  clip-path: inset(50%);
  inline-size: 1px;
  overflow: hidden;
  position: absolute;
  white-space: nowrap;
}

@media (max-width: 36rem) {
  .mrg-stepper ol {
    display: grid;
  }

  .mrg-stepper li:not(:last-child)::after {
    block-size: calc(100% - var(--mrg-semantic-size-target-preferred));
    inline-size: var(--mrg-semantic-border-width-strong);
    inset-block-start: calc(50% + var(--mrg-semantic-size-target-preferred) / 2);
    inset-inline-start: calc(var(--mrg-semantic-size-target-preferred) / 2);
  }

  .mrg-stepper__control {
    flex-direction: row;
    text-align: start;
  }
}

@media (prefers-reduced-motion: reduce) {
  .mrg-stepper__control,
  .mrg-stepper__marker {
    transition: none;
  }
}

@media (forced-colors: active) {
  .mrg-stepper__marker,
  .mrg-stepper li[data-state] .mrg-stepper__marker,
  .mrg-stepper__summary {
    background: Canvas;
    color: CanvasText;
    forced-color-adjust: auto;
  }

  .mrg-stepper li[data-state="current"] .mrg-stepper__marker,
  .mrg-stepper li[data-state="complete"] .mrg-stepper__marker {
    border-color: Highlight;
  }

  .mrg-stepper__control:focus-visible {
    box-shadow: none;
    outline-color: Highlight;
  }
}

"use client";

import {
  Fragment,
  forwardRef,
  isValidElement,
  useState,
  type MouseEvent,
  type ReactNode,
} from "react";

import "./stepper.css";

export type StepperMode = "linear" | "nonlinear";
export type StepperStepState = "complete" | "current" | "error" | "upcoming";

export interface StepperStep {
  /** Optional visible supporting copy rendered beneath the step label. */
  readonly description?: ReactNode;
  /** Keeps the step visible but removes its activation control and marks it disabled. */
  readonly disabled?: boolean;
  /** Non-empty unique identity used by controlled and uncontrolled current-step state. */
  readonly id: string;
  /** Visible step name used by controls and optional completion announcements. */
  readonly label: ReactNode;
  /** Explicit non-current status; the active identity always resolves to current. */
  readonly state?: Exclude<StepperStepState, "current">;
}

export interface StepperProgressContext {
  /** Zero-based position of the current step in the validated steps array. */
  readonly currentIndex: number;
  /** Complete current-step record supplied to the optional summary formatter. */
  readonly currentStep: StepperStep;
  /** Active reachability policy supplied to the optional summary formatter. */
  readonly mode: StepperMode;
  /** Total number of validated steps represented by the stepper. */
  readonly total: number;
}

function hasAccessibleContent(value: ReactNode): boolean {
  if (value === null || value === undefined || typeof value === "boolean") return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.some(hasAccessibleContent);
  if (isValidElement<{ readonly children?: ReactNode }>(value)) {
    if (value.type === Fragment) return hasAccessibleContent(value.props.children);
    return true;
  }
  return true;
}

export interface StepperProps extends Omit<
  React.ComponentPropsWithoutRef<"nav">,
  "children" | "onChange"
> {
  /** Adds a polite completion status after the list; false removes the live region entirely. */
  readonly announceStepChanges?: boolean;
  /** Initial current-step identity for uncontrolled use, defaulting to the first step. */
  readonly defaultValue?: string;
  /** Accessible name for the navigation landmark and optional native progress element. */
  readonly label?: string;
  /** Linear limits activation to reached or next steps; nonlinear permits any enabled step. */
  readonly mode?: StepperMode;
  /** Renders reachable steps as native buttons; false keeps the stepper read-only. */
  readonly navigable?: boolean;
  /** Receives button activation before state changes; preventDefault cancels selection. */
  readonly onStepActivate?: (event: MouseEvent<HTMLButtonElement>, step: StepperStep) => void;
  /** Reports each proposed current-step identity in controlled and uncontrolled modes. */
  readonly onValueChange?: (id: string) => void;
  /** Optional visible progress context. Omission does not call the formatter or emit output. */
  readonly renderProgressSummary?: (context: StepperProgressContext) => ReactNode;
  /** Optional native progress semantics, independently removable from announcements and summary. */
  readonly showProgressBar?: boolean;
  /** Non-empty DOM-ordered model retained when the visual layout stacks on narrow screens. */
  readonly steps: readonly StepperStep[];
  /** Controlled current-step identity; pair with onValueChange to accept proposals. */
  readonly value?: string;
}

export const Stepper = forwardRef<HTMLElement, StepperProps>(function Stepper(
  {
    announceStepChanges = false,
    className,
    defaultValue,
    label = "Progress",
    mode = "linear",
    navigable = false,
    onStepActivate,
    onValueChange,
    renderProgressSummary,
    showProgressBar = false,
    steps,
    value,
    ...props
  },
  ref,
) {
  if (steps.length === 0) throw new Error("Mergora Stepper requires at least one step.");
  const ids = new Set<string>();
  for (const step of steps) {
    if (step.id.trim().length === 0 || ids.has(step.id)) {
      throw new Error("Mergora Stepper step ids must be non-empty and unique.");
    }
    ids.add(step.id);
  }
  const initialValue = defaultValue ?? steps[0]?.id;
  const [uncontrolledValue, setUncontrolledValue] = useState(initialValue);
  const resolvedValue = value ?? uncontrolledValue;
  const currentIndex = steps.findIndex((step) => step.id === resolvedValue);
  if (currentIndex < 0) throw new Error("Mergora Stepper value must identify a step.");
  const currentStep = steps[currentIndex];
  if (currentStep === undefined) throw new Error("Mergora Stepper current step is unavailable.");
  const context: StepperProgressContext = {
    currentIndex,
    currentStep,
    mode,
    total: steps.length,
  };
  const progressSummary = renderProgressSummary?.(context);
  const setValue = (next: string) => {
    if (value === undefined) setUncontrolledValue(next);
    onValueChange?.(next);
  };

  return (
    <nav
      {...props}
      aria-label={label}
      className={["mrg-stepper", className].filter(Boolean).join(" ")}
      data-mode={mode}
      data-slot="stepper"
      ref={ref}
    >
      {showProgressBar ? (
        <progress
          aria-label={`${label}: ${String(currentIndex + 1)} of ${String(steps.length)}`}
          data-slot="stepper-progress"
          max={steps.length}
          value={currentIndex + 1}
        />
      ) : null}
      {hasAccessibleContent(progressSummary) ? (
        <div className="mrg-stepper__summary" data-slot="stepper-summary">
          {progressSummary}
        </div>
      ) : null}
      <ol data-slot="stepper-list">
        {steps.map((step, index) => {
          const error = step.state === "error";
          const state: StepperStepState =
            index === currentIndex
              ? "current"
              : (step.state ?? (index < currentIndex ? "complete" : "upcoming"));
          const reachable =
            !step.disabled && navigable && (mode === "nonlinear" || index <= currentIndex + 1);
          const content = (
            <>
              <span aria-hidden="true" className="mrg-stepper__marker">
                {state === "complete" ? "✓" : String(index + 1)}
              </span>
              <span className="mrg-stepper__copy">
                <span data-slot="stepper-label">
                  {error ? <span className="mrg-stepper__visually-hidden">Error: </span> : null}
                  {step.label}
                </span>
                {step.description === undefined ? null : <small>{step.description}</small>}
              </span>
            </>
          );
          return (
            <li
              data-error={error ? "" : undefined}
              data-state={state}
              data-slot="stepper-step"
              key={step.id}
            >
              {reachable ? (
                <button
                  aria-current={state === "current" ? "step" : undefined}
                  aria-invalid={error || undefined}
                  className="mrg-stepper__control"
                  onClick={(event) => {
                    onStepActivate?.(event, step);
                    if (!event.defaultPrevented) setValue(step.id);
                  }}
                  type="button"
                >
                  {content}
                </button>
              ) : (
                <span
                  aria-current={state === "current" ? "step" : undefined}
                  aria-disabled={
                    step.disabled || (navigable && index > currentIndex + 1) || undefined
                  }
                  aria-invalid={error || undefined}
                  className="mrg-stepper__control"
                >
                  {content}
                </span>
              )}
            </li>
          );
        })}
      </ol>
      {announceStepChanges ? (
        <span
          aria-live="polite"
          className="mrg-stepper__announcement"
          data-slot="stepper-announcement"
          role="status"
        >
          Step {currentIndex + 1} of {steps.length}: {currentStep.label}
        </span>
      ) : null}
    </nav>
  );
});

Stepper.displayName = "Stepper";
